const body = $input.first().json.body || $input.first().json;
return [{
  json: {
    cotizacion_id:  (body.cotizacion_id  || '').trim(),
    opcion_elegida: (body.opcion_elegida || '').trim().toLowerCase(),
    metodo_pago:    (body.metodo_pago    || '').trim(),
    modalidad:      (body.modalidad      || '').trim().toLowerCase(),
    direccion:      (body.direccion      || '').trim()
  }
}];

const d = $input.first().json;
if (!d.cotizacion_id)
  return [{ json: { ...d, valido: false, error_code: 400, error_msg: 'cotizacion_id es requerido' } }];
if (!['marca', 'economico'].includes(d.opcion_elegida))
  return [{ json: { ...d, valido: false, error_code: 422, error_msg: 'opcion_elegida debe ser marca o economico. Recibido: ' + d.opcion_elegida } }];
if (!d.metodo_pago)
  return [{ json: { ...d, valido: false, error_code: 422, error_msg: 'metodo_pago es requerido' } }];
if (!['retiro', 'envio'].includes(d.modalidad))
  return [{ json: { ...d, valido: false, error_code: 422, error_msg: 'modalidad debe ser retiro o envio. Recibido: ' + d.modalidad } }];
if (d.modalidad === 'envio' && !d.direccion)
  return [{ json: { ...d, valido: false, error_code: 422, error_msg: 'direccion es requerida cuando modalidad es envio' } }];
return [{ json: { ...d, valido: true } }];

const inputData = $('Normalizar Input').first().json;
const cotizacion_id = inputData.cotizacion_id;
const fila = $input.all().find(item => item.json.cotizacion_id === cotizacion_id)?.json;

if (!fila)
  return [{ json: { ...inputData, cotizacion_ok: false, error_code: 404, error_msg: 'Cotizacion no encontrada: ' + cotizacion_id } }];

if (fila.estado !== 'cotizado') {
  let msg;
  if (['elegido_marca', 'elegido_economico'].includes(fila.estado))
    msg = 'Ya confirmada con opcion: ' + fila.estado.replace('elegido_', '');
  else if (fila.estado === 'comprobante_enviado')
    msg = 'Ya tiene comprobante enviado.';
  else
    msg = 'Estado invalido: ' + fila.estado + '. Se requiere: cotizado';
  return [{ json: { ...inputData, cotizacion_ok: false, error_code: 409, error_msg: msg, estado_actual: fila.estado } }];
}

return [{
  json: {
    ...inputData,
    cotizacion_ok: true,
    cotizacion: {
      nombre:          fila.nombre          || '',
      telefono:        fila.telefono        || '',
      colegio:         fila.colegio         || '',
      grado:           fila.grado           || '',
      total_marca:     parseFloat(fila.total_marca)     || 0,
      total_economico: parseFloat(fila.total_economico) || 0,
      fecha_original:  fila.fecha
    }
  }
}];

const d = $input.first().json;
const cot = d.cotizacion;
const total = d.opcion_elegida === 'marca' ? cot.total_marca : cot.total_economico;
if (total <= 0) throw new Error('Total invalido para opcion ' + d.opcion_elegida + ': ' + total);
return [{
  json: {
    cotizacion_id:      d.cotizacion_id,
    nombre:             cot.nombre,
    telefono:           d.telefono || cot.telefono,
    colegio:            cot.colegio,
    grado:              cot.grado,
    opcion:             d.opcion_elegida,
    total:              Math.round(total * 100) / 100,
    metodo_pago:        d.metodo_pago,
    modalidad:          d.modalidad,
    direccion:          d.direccion || '',
    estado:             'pendiente_pago',
    fecha_pedido:       new Date().toISOString(),
    nuevo_estado:       d.opcion_elegida === 'marca' ? 'elegido_marca' : 'elegido_economico',
    datos_pago:         $env.DATOS_PAGO         || 'Sin configurar',
    direccion_libreria: $env.DIRECCION_LIBRERIA  || 'Sin configurar'
  }
}];
